SELECT player_id, tournament_id, average_score
FROM player_tournament_statistics
WHERE player_id = 1 AND tournament_id = 1;

SELECT COUNT(DISTINCT player_id) AS unique_winners
FROM tournament_results
WHERE place = 'Winner';

SELECT p.player_id, p.player_name, ps.average_score AS career_average_score
FROM players p
JOIN player_statistics ps ON p.player_id = ps.player_id;

SELECT player_name 
FROM players 
WHERE player_id BETWEEN 3 AND 8;

SELECT COUNT(*) 
FROM player_handicaps 
WHERE handicap_index > 3;
